#include<iostream>
using namespace std;
bool zs(int x) {
	for(int i=2; i<x; i++) {
		if(x%i==0) {
			return 0;
		}
	}
	return 1;
}
long long n,a[1005];
int main() {
	cin>>n;
	a[0]=1;
	for(int i=2; i<=n; i++) {
		if(!zs(i)) {
			continue;
		}
		for(int j=0; j<=n; j++) {
			if(a[j]&&j+i<=n) {
				a[j+i]+=a[j];
			}
		}
	}
	cout<<a[n];
	return 0;
}
